\end{align*}

\begin{align*}
countfunc(limitvar) &\leq \sum_{indexvar=1}^{\lceil \sqrt{limitvar} \rceil} (2 \sqrt{indexvar} + 1) \\
&\leq \int_0^{\lceil \sqrt{limitvar}\rceil + 1} 2 \sqrt{dummyvar}\,d dummyvar  + \sqrt{limitvar} + 1\\
